import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Escaping user input before displaying it on a web page
        String safeUserInput = Encode.forHtml(userInput);

        // Displaying the sanitized user input on a web page
        String outputHtml = "<html><body><h1>User Input:</h1>" + safeUserInput + "</body></html>";

        System.out.println(outputHtml);
    }
}

